import httpx, json

BILI_HOT_URL = 'https://s.search.bilibili.com/main/hotword'
WEIBO_HOT_URL = 'https://weibo.com/ajax/side/hotSearch'
HEADERS = {'User-Agent': 'Mozilla/5.0 (iPhone; CPU iPhone OS 17_0 like Mac OS X) AppleWebKit/605.1.15'}
topics = []

try:
    r = httpx.get(BILI_HOT_URL, timeout=10, headers=HEADERS)
    r.raise_for_status()
    bili_items = r.json().get('list', [])
    for idx, item in enumerate(bili_items[:15]):
        topics.append({
            'source':  'bilibili',
            'keyword': item.get('show_name') or item.get('keyword', ''),
            'heat':    1000 - idx,
            'icon':    ''
        })
except Exception as e_bili:
    try:
        r = httpx.get(WEIBO_HOT_URL, timeout=10, headers=HEADERS)
        r.raise_for_status()
        realtime = r.json().get('data', {}).get('realtime', [])[:15]
        for item in realtime:
            topics.append({
                'source':  'weibo',
                'keyword': item.get('word', ''),
                'heat':    item.get('num', 0),
                'icon':    item.get('icon_desc', '')
            })
    except Exception as e_weibo:
        topics.append({'source': 'fallback', 'keyword': 'AI人工智能', 'heat': 9999, 'icon': '爆'})

topics.sort(key=lambda x: x['heat'], reverse=True)
selected = topics[0] if topics else {'keyword': 'AI最新进展', 'source': 'fallback', 'heat': 0, 'icon': ''}

return [{'json': {'topics': topics, 'selected': selected}}]
